const item = $input.first().json;
const webhook = String(item.slackWebhookUrl || '').trim();
if (!webhook) {
  throw new Error('Set slackWebhookUrl in the previous node (Slack Incoming Webhook URL).');
}
const pairs = [
  ['uptime', 'https://uptime.aware-wave.com/dashboard'],
  ['app', 'https://app.aware-wave.com/'],
  ['api', 'https://api.aware-wave.com/health'],
  ['n8n', 'https://n8n.aware-wave.com/healthz'],
];
const rows = [];
for (const [name, url] of pairs) {
  let code = 200;
  let err = '';
  try {
    await this.helpers.httpRequest({ method: 'GET', url, timeout: 15000 });
  } catch (e) {
    code = 599;
    err = String(e.message || e).slice(0, 240);
  }
  const ok = code >= 200 && code < 400;
  rows.push({ name, url, code, ok, err });
}
const lines = rows.map((r) => {
  const mark = r.ok ? 'OK' : 'FAIL';
  return mark + ' ' + r.name + ' ' + r.code + ' ' + r.url;
});
const summary = '*SLO weekly probe* (UTC ' + new Date().toISOString() + ')\n' + lines.join('\n');
return [{ json: { summary, slackWebhookUrl: webhook, rows } }];
